const body = $input.first().json.body || $input.first().json || {};
const action = body.action || 'get_all'; // get_all, get_sales, get_profit, get_inventory, refresh, get_alerts
const dateRange = body.date_range || {};
const platform = body.platform;
const isScheduled = !$input.first().json.body;
return [{ json: { action: isScheduled ? 'refresh' : action, date_range: dateRange, platform, is_scheduled: isScheduled } }];

const dailySales = $node['📈 日別売上集計'].json;
const platformBreakdown = $node['📊 販路別集計'].json;
const profitTrend = $node['💰 利益推移集計'].json;
const inventory = $node['📦 在庫カテゴリ集計'].json;

const today = new Date().toISOString().split('T')[0];

const metrics = [
  { metric_type: 'daily_sales', metric_date: today, metric_data: { data: Array.isArray(dailySales) ? dailySales : [dailySales] } },
  { metric_type: 'platform_breakdown', metric_date: today, metric_data: { data: Array.isArray(platformBreakdown) ? platformBreakdown : [platformBreakdown] } },
  { metric_type: 'profit_trend', metric_date: today, metric_data: { data: Array.isArray(profitTrend) ? profitTrend : [profitTrend] } },
  { metric_type: 'inventory_breakdown', metric_date: today, metric_data: { data: Array.isArray(inventory) ? inventory : [inventory] } }
];

return metrics.map(m => ({ json: m }));

const profitTrend = $node['💰 利益推移集計'].json;
const thresholdRaw = $input.first().json;
const threshold = parseFloat(thresholdRaw?.setting_value) || 0.10;

const profits = Array.isArray(profitTrend) ? profitTrend : [profitTrend];
const alerts = [];

// 利益率低下チェック
if (profits.length >= 2) {
  const latest = profits[0];
  const previous = profits[1];
  if (latest && previous && latest.avg_margin && previous.avg_margin) {
    const drop = previous.avg_margin - latest.avg_margin;
    if (drop > threshold) {
      alerts.push({
        alert_type: 'profit_drop',
        alert_severity: drop > 0.20 ? 'critical' : 'warning',
        alert_title: '利益率低下アラート',
        alert_message: `利益率が${Math.round(drop * 100)}%低下しました（${Math.round(previous.avg_margin * 100)}% → ${Math.round(latest.avg_margin * 100)}%）`,
        alert_data: { previous_margin: previous.avg_margin, current_margin: latest.avg_margin, drop: drop }
      });
    }
  }
}

return alerts.length > 0 ? alerts.map(a => ({ json: a })) : [{ json: { no_alerts: true } }];

const action = $node['🔐 初期化'].json.action;
let result = { success: true, action, timestamp: new Date().toISOString() };

if (action === 'get_all') {
  const metrics = $node['📊 全メトリクス取得'].json;
  result.metrics = Array.isArray(metrics) ? metrics : (metrics?.metric_type ? [metrics] : []);
} else if (action === 'get_alerts') {
  const alerts = $node['🚨 アラート取得'].json;
  result.alerts = Array.isArray(alerts) ? alerts : (alerts?.id ? [alerts] : []);
} else if (action === 'refresh') {
  result.message = 'メトリクス更新完了';
  result.metrics_updated = 4;
}

return [{ json: result }];

// N3 HMAC署名検証（要塞化自動挿入）
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || $input.first().json;

const signature = headers['x-n3-signature'] || headers['X-N3-Signature'] || '';
const timestamp = headers['x-n3-timestamp'] || headers['X-N3-Timestamp'] || '';

if (signature && timestamp) {
  const secret = $env.N3_HMAC_SECRET;
  if (!secret) {
    return [{ json: { error: true, message: 'N3_HMAC_SECRET 環境変数が未設定', code: 'CONFIG_ERROR' } }];
  }

  const ts = parseInt(timestamp, 10);
  const now = Math.floor(Date.now() / 1000);
  if (Math.abs(now - ts) > 300) {
    return [{ json: { error: true, message: 'タイムスタンプ期限切れ', code: 'TIMESTAMP_EXPIRED' } }];
  }

  try {
    const verifyUrl = $env.PRICING_ENGINE_URL || 'http://localhost:8000';
    const payload = JSON.stringify(body);
    const response = await fetch(`${verifyUrl}/verify-signature`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ payload, signature, timestamp })
    });
    const result = await response.json();
    if (!result.valid) {
      return [{ json: { error: true, message: '署名検証失敗: ' + (result.error || ''), code: 'INVALID_SIGNATURE' } }];
    }
  } catch (e) {
    console.log('署名検証スキップ: ' + e.message);
  }
}

return $input.all();
